Code:
public boolean xyBalance(String str) {
    int xCount = 0;
    boolean lastCharIsY = false;
    for (int i = 0; i < str.length(); i++) {
        char c = str.charAt(i);
        if (c == 'x') {
            xCount++;
            lastCharIsY = false;
        } else if (c == 'y') {
            if (xCount > 0) {
                xCount--;
                lastCharIsY = true;
            } else {
                lastCharIsY = false;
            }
        }
    }
    return xCount == 0;
}

